import{_ as p}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{B as r,c as B,f as o,q as E,D as A,O as e,j as n,g as l,k as t,X as u}from"./chunks/runtime-core.esm-bundler.DoiTk7Jm.js";const b=JSON.parse('{"title":"从卷模型到卷产品：AI应用层的机会在哪","description":"","frontmatter":{},"headers":[],"relativePath":"column/AIFuture/趋势观察/从卷模型到卷产品：AI应用层的机会在哪.md","filePath":"column/AIFuture/趋势观察/从卷模型到卷产品：AI应用层的机会在哪.md","lastUpdated":1782975799000}'),d={name:"column/AIFuture/趋势观察/从卷模型到卷产品：AI应用层的机会在哪.md"};function _(h,a,q,I,m,c){const s=r("ArticleMetadata"),i=r("Mermaid");return o(),B("div",null,[a[2]||(a[2]=E("h1",{id:"从卷模型到卷产品-ai应用层的机会在哪",tabindex:"-1"},[l("从卷模型到卷产品：AI应用层的机会在哪 "),E("a",{class:"header-anchor",href:"#从卷模型到卷产品-ai应用层的机会在哪","aria-label":'Permalink to "从卷模型到卷产品：AI应用层的机会在哪"'},"​")],-1)),A(s),a[3]||(a[3]=e('<p>去年所有人都在追 SOTA。谁的模型跑分高一点，朋友圈能刷屏三天。</p><p>今年风向明显变了。</p><p>各家基础模型的差距在快速缩小。GPT-4 级别的能力正在变成标配而非卖点。于是战场悄悄从&quot;谁的模型更强&quot;转移到了&quot;谁能用模型做出好产品&quot;。</p><p>这不是我猜的，你看看周围：去年融资最多的是模型公司，今年在闷声赚钱的是把 AI 嵌入到具体业务场景里的团队。</p><h2 id="模型在贬值-场景在升值" tabindex="-1">模型在贬值，场景在升值 <a class="header-anchor" href="#模型在贬值-场景在升值" aria-label="Permalink to &quot;模型在贬值，场景在升值&quot;">​</a></h2><p>一个很直观的信号：API 调用价格一直在降。GPT-4 刚出来的时候贵得离谱，现在同类能力的价格可能只有当时的十分之一。</p><p>这意味着什么？</p><p><strong>靠模型能力本身做差异化的窗口在快速关闭。</strong> 你能调的模型，别人也能调。你能用的 RAG、Agent、MCP，别人也能用。</p><p>那什么东西别人抄不走？</p><ul><li>你对某个行业的理解深度</li><li>你自己的数据积累</li><li>你跟用户建立的信任关系</li><li>你把 AI 嵌入到具体工作流的方式</li></ul>',10)),(o(),n(u,null,{default:t(()=>[A(i,{id:"mermaid-52",class:"mermaid",graph:"flowchart%20LR%0A%20%20A%5B%22%E6%A8%A1%E5%9E%8B%E8%83%BD%E5%8A%9B%EF%BC%88%E5%90%8C%E8%B4%A8%E5%8C%96%EF%BC%89%22%5D%20--%3E%20B%5B%22%E5%BA%94%E7%94%A8%E5%B1%82%E5%B7%AE%E5%BC%82%22%5D%0A%20%20B%20--%3E%20C%5B%22%E8%A1%8C%E4%B8%9A%20know-how%22%5D%0A%20%20B%20--%3E%20D%5B%22%E7%A7%81%E6%9C%89%E6%95%B0%E6%8D%AE%22%5D%0A%20%20B%20--%3E%20E%5B%22%E5%B7%A5%E4%BD%9C%E6%B5%81%E8%AE%BE%E8%AE%A1%22%5D%0A%20%20B%20--%3E%20F%5B%22%E7%94%A8%E6%88%B7%E4%BF%A1%E4%BB%BB%22%5D%0A"})]),fallback:t(()=>[...a[0]||(a[0]=[l(" Loading... ",-1)])]),_:1})),a[4]||(a[4]=e('<h2 id="哪些方向有真实需求" tabindex="-1">哪些方向有真实需求？ <a class="header-anchor" href="#哪些方向有真实需求" aria-label="Permalink to &quot;哪些方向有真实需求？&quot;">​</a></h2><p>说几个我实际看到有人在闷声干、而且用户愿意付费的方向：</p><h3 id="垂直行业的-ai-助手" tabindex="-1">垂直行业的 AI 助手 <a class="header-anchor" href="#垂直行业的-ai-助手" aria-label="Permalink to &quot;垂直行业的 AI 助手&quot;">​</a></h3><p>不是泛泛的&quot;AI 客服&quot;，而是真正懂一个行业的：</p><ul><li>律师事务所的合同审查助手（不是通用 PDF 问答，是懂法条、懂判例、懂客户行业）</li><li>诊所的病历整理和辅助诊断（不是替代医生，是帮医生省打字和翻资料的时间）</li><li>外贸公司的邮件和单据处理（懂报关流程、懂各国合规要求）</li></ul><p>这些场景的共同点是：<strong>门外汉看起来很简单，但真正做起来全是行业细节。</strong> 而细节就是护城河。</p><h3 id="企业内部工作流自动化" tabindex="-1">企业内部工作流自动化 <a class="header-anchor" href="#企业内部工作流自动化" aria-label="Permalink to &quot;企业内部工作流自动化&quot;">​</a></h3><p>不是 RPA，是 AI + 流程。</p><p>比如一个采购流程：</p><ol><li>员工提交采购申请</li><li>AI 自动查历史价格、供应商资质、预算余额</li><li>低于 5000 且合规 → 自动审批</li><li>否则 → 推给对应审批人，附上 AI 整理的所有信息</li></ol><p>这类产品的价值不在于 AI 多聪明，在于<strong>把原来需要翻五个系统、打三个电话的事，变成一次对话能解决的体验。</strong></p><h3 id="开发者的-ai-原生工具" tabindex="-1">开发者的 AI 原生工具 <a class="header-anchor" href="#开发者的-ai-原生工具" aria-label="Permalink to &quot;开发者的 AI 原生工具&quot;">​</a></h3><p>码农的钱最好赚，前提是你真的解决了痛点：</p><ul><li>不是&quot;AI 帮你写代码&quot;（这个太卷了），而是&quot;AI 帮你理解为什么当年那个同事写了这行代码&quot;</li><li>不是&quot;AI 生成文档&quot;，而是&quot;代码改了文档自动更新，不需要任何人提醒&quot;</li><li>不是&quot;AI 做 Code Review&quot;，而是&quot;AI 帮你找出这次改动对哪些下游系统有影响&quot;</li></ul><p>做工具不难，难的是做到<strong>少一个步骤都不行</strong>的体验。</p><h2 id="做-ai-产品最容易犯的三个错" tabindex="-1">做 AI 产品最容易犯的三个错 <a class="header-anchor" href="#做-ai-产品最容易犯的三个错" aria-label="Permalink to &quot;做 AI 产品最容易犯的三个错&quot;">​</a></h2><h3 id="_1-把-ai-当卖点" tabindex="-1">1. 把 AI 当卖点 <a class="header-anchor" href="#_1-把-ai-当卖点" aria-label="Permalink to &quot;1. 把 AI 当卖点&quot;">​</a></h3><p>&quot;我们是 AI 驱动的 XX 平台&quot;——用户根本不在乎你是不是 AI 驱动，只在乎你解没解决他的问题。</p><p>好的 AI 产品是 <strong>&quot;用了 AI 但用户感觉不到 AI&quot;</strong>。比如 Notion 的 AI，你不会说&quot;我要用 AI 写文档&quot;，你只是在写文档的过程中顺手用了。</p><h3 id="_2-堆功能-不解决真问题" tabindex="-1">2. 堆功能，不解决真问题 <a class="header-anchor" href="#_2-堆功能-不解决真问题" aria-label="Permalink to &quot;2. 堆功能，不解决真问题&quot;">​</a></h3><p>做了个&quot;AI 合同助手&quot;，功能列了一长串：智能起草、风险识别、条款对比、法律检索、自动归档...</p><p>但用户打开后，第一件事还是手动复制粘贴合同内容进去。入口体验就断了。</p><p><strong>先做好一个场景到极致，再扩展。</strong> 贪多嚼不烂在 AI 产品上尤其适用。</p><h3 id="_3-忽视-ai-的不可靠性" tabindex="-1">3. 忽视 AI 的不可靠性 <a class="header-anchor" href="#_3-忽视-ai-的不可靠性" aria-label="Permalink to &quot;3. 忽视 AI 的不可靠性&quot;">​</a></h3><p>模型的回答有时候会瞎编，这是客观事实，不是&quot;再优化优化就能解决&quot;的。</p><p>好的产品设计不是祈祷模型不出错，而是<strong>设计了模型出错时的兜底方案</strong>：</p><ul><li>给用户展示信息来源</li><li>不确定的时候主动标注&quot;建议人工核实&quot;</li><li>关键操作必须确认</li></ul><h2 id="应用层真正在卷什么" tabindex="-1">应用层真正在卷什么？ <a class="header-anchor" href="#应用层真正在卷什么" aria-label="Permalink to &quot;应用层真正在卷什么？&quot;">​</a></h2>',28)),(o(),n(u,null,{default:t(()=>[A(i,{id:"mermaid-198",class:"mermaid",graph:"mindmap%0A%20%20root((AI%E5%BA%94%E7%94%A8%E5%B1%82%E7%AB%9E%E4%BA%89%E5%8A%9B))%0A%20%20%20%20%E8%A1%8C%E4%B8%9A%E7%90%86%E8%A7%A3%0A%20%20%20%20%20%20%E4%B8%9A%E5%8A%A1%E8%A7%84%E5%88%99%0A%20%20%20%20%20%20%E9%9A%90%E6%80%A7%E7%9F%A5%E8%AF%86%0A%20%20%20%20%20%20%E7%94%A8%E6%88%B7%E4%B9%A0%E6%83%AF%0A%20%20%20%20%E6%95%B0%E6%8D%AE%E5%A3%81%E5%9E%92%0A%20%20%20%20%20%20%E7%A7%81%E6%9C%89%E6%95%B0%E6%8D%AE%0A%20%20%20%20%20%20%E5%8F%8D%E9%A6%88%E9%97%AD%E7%8E%AF%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E9%A3%9E%E8%BD%AE%0A%20%20%20%20%E7%94%A8%E6%88%B7%E4%BD%93%E9%AA%8C%0A%20%20%20%20%20%20%E4%BA%A4%E4%BA%92%E8%AE%BE%E8%AE%A1%0A%20%20%20%20%20%20%E9%94%99%E8%AF%AF%E5%A4%84%E7%90%86%0A%20%20%20%20%20%20%E6%B8%90%E8%BF%9B%E5%BC%8F%E5%BC%95%E5%AF%BC%0A%20%20%20%20%E4%BF%A1%E4%BB%BB%E4%BD%93%E7%B3%BB%0A%20%20%20%20%20%20%E5%8F%AF%E8%A7%A3%E9%87%8A%E6%80%A7%0A%20%20%20%20%20%20%E8%B4%A8%E9%87%8F%E4%BF%9D%E8%AF%81%0A%20%20%20%20%20%20%E5%AE%89%E5%85%A8%E5%90%88%E8%A7%84%0A"})]),fallback:t(()=>[...a[1]||(a[1]=[l(" Loading... ",-1)])]),_:1})),a[5]||(a[5]=e('<p>这些没有一个跟模型能力直接相关。这才是应用层的机会所在。</p><h2 id="给想做-ai-产品的人几句实在话" tabindex="-1">给想做 AI 产品的人几句实在话 <a class="header-anchor" href="#给想做-ai-产品的人几句实在话" aria-label="Permalink to &quot;给想做 AI 产品的人几句实在话&quot;">​</a></h2><ol><li><p><strong>别盯着模型跑分找灵感</strong>。跑分高不代表场景成立。反过来想：哪些事之前因为太贵/太慢/太麻烦做不了，现在 AI 让它变得可行了？</p></li><li><p><strong>先在一个小场景做到 80 分再扩展</strong>。别一上来就想做平台。把一个场景做透了，用户会帮你找到下一个场景。</p></li><li><p><strong>数据的价值会在未来两年集中兑现</strong>。你有别人没有的数据，比你有别人没有的模型重要得多。</p></li><li><p><strong>别怕大厂</strong>。大厂做平台，你做垂直。大厂追求通用，你可以追求&quot;就这一个行业、就这一种用户、就这一个场景&quot;的极致体验。</p></li></ol><blockquote><p>模型能力在趋同，但好产品和烂产品之间的距离，从来不是模型拉开的。</p></blockquote><hr><p><em>延伸阅读</em></p><ul><li><a href="https://a16z.com/the-state-of-ai-2025/" target="_blank" rel="noreferrer">a16z：The State of AI in 2025</a></li><li><a href="https://www.sequoiacap.com/article/generative-ai-act-o1/" target="_blank" rel="noreferrer">Sequoia：Generative AI&#39;s Act o1</a></li></ul>',7))])}const P=p(d,[["render",_]]);export{b as __pageData,P as default};
